#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e6+5;
const LL MOD = 19930726;
LL n,k,p[N],t[N],cnt,Ans=1;string s;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(LL x,LL y){return x>y;}
LL QP(LL x,LL y){
    LL as=1;
    while(y){
        if(y&1)as=(as*x)%MOD;
        x=(x*x)%MOD,y>>=1;
    }return as;
}
int main(){
    n=read(),k=read();cin>>s;s=" "+s;
    for(LL i=1,l=0,r=-1;i<=n;i++){
        LL len=(i>r?1:min(p[l+r-i],r-i+1));
        while(i-len>=1&&i+len<=n&&s[i-len]==s[i+len])len++;
        p[i]=len,t[p[i]*2-1]++;
        if(i+len-1>r)l=i-len+1,r=i+len-1;
    }for(LL i=n;i>=1;i--){
        if(i%2==0)continue;cnt+=t[i];
        Ans=(Ans*QP(i,min(k,cnt)))%MOD;
        if(cnt<k)k-=cnt;else{k=0;break;}
    }if(k)Ans=-1;cout<<Ans<<"\n";
    return 0;
}
